                    b.Property<uint>("FastestLapTime")
                        .HasColumnType("int unsigned");

                    b.Property<int>("FinishPosition")
                        .HasColumnType("int");

                    b.Property<int>("GridPosition")
                        .HasColumnType("int");

                    b.Property<int>("LapsDriven")
                        .HasColumnType("int");

                    b.Property<uint>("NumberOfPenalties")
                        .HasColumnType("int unsigned");

                    b.Property<long>("ParticipantId")
                        .HasColumnType("bigint");

                    b.Property<uint>("PenaltiesTime")
                        .HasColumnType("int unsigned");

                    b.Property<int>("PitStops")
                        .HasColumnType("int");

                    b.Property<int>("ResultStatus")
                        .HasColumnType("int");

                    b.Property<long>("SessionId")
                        .HasColumnType("bigint");

                    b.Property<double>("TotalRaceTime")
                        .HasColumnType("double");

                    b.HasKey("Id");

                    b.HasIndex("ParticipantId");

                    b.HasIndex("SessionId");

                    b.HasIndex("SessionId", "ParticipantId");

                    b.ToTable("FinalClassifications", t =>
                        {
                            t.HasComment("Entity of final classification of session, contains results of participants after the session ends.");
                        });
                });

